<?php
namespace Tests\Feature\Repayments;
use App\Domain\Repayments\Actions\RecordLoanRepayment;use App\Domain\Repayments\Actions\ReverseLoanRepayment;use App\Enums\LoanApplicationStatus;use App\Enums\LoanStatus;use App\Models\ApprovalWorkflow;use App\Models\Cooperative;use App\Models\Loan;use App\Models\LoanApplication;use App\Models\LoanProduct;use App\Models\Member;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class LoanRepaymentTest extends TestCase{use RefreshDatabase;private function loan():Loan{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);$member=Member::factory()->create(['cooperative_id'=>$cooperative->id]);$workflow=ApprovalWorkflow::query()->create(['name'=>'Loan approval','code'=>'LOAN','entity_type'=>'loan_application','is_active'=>true]);$product=LoanProduct::factory()->create(['cooperative_id'=>$cooperative->id,'approval_workflow_id'=>$workflow->id]);$application=LoanApplication::query()->create(['member_id'=>$member->id,'loan_product_id'=>$product->id,'approval_workflow_id'=>$workflow->id,'reference'=>'LAP-TEST','requested_principal_minor'=>100000,'tenure'=>1,'purpose'=>'Test','status'=>LoanApplicationStatus::Disbursed,'applicant_snapshot'=>[]]);$loan=Loan::query()->create(['loan_application_id'=>$application->id,'member_id'=>$member->id,'loan_product_id'=>$product->id,'loan_number'=>'LN-TEST','principal_minor'=>100000,'interest_minor'=>10000,'charges_added_minor'=>5000,'repayable_minor'=>115000,'outstanding_minor'=>115000,'status'=>LoanStatus::Active,'disbursed_at'=>today(),'maturity_date'=>today()->addMonth()]);$loan->installments()->create(['installment_number'=>1,'due_date'=>today()->addMonth(),'principal_due_minor'=>100000,'interest_due_minor'=>10000,'charges_due_minor'=>5000,'penalties_due_minor'=>2000,'status'=>'upcoming']);$loan->increment('outstanding_minor',2000);return $loan->refresh();}public function test_partial_repayment_allocates_penalty_charges_interest_then_principal():void{$loan=$this->loan();$repayment=app(RecordLoanRepayment::class)->execute($loan,['idempotency_key'=>'repay-001','channel'=>'bank_transfer','amount_minor'=>20000]);$this->assertSame(['penalties','charges','interest','principal'],$repayment->allocations->pluck('component')->all());$this->assertSame([2000,5000,10000,3000],$repayment->allocations->pluck('amount_minor')->all());$this->assertSame(97000,$loan->refresh()->outstanding_minor);}public function test_reversal_restores_component_and_loan_balances():void{$loan=$this->loan();$repayment=app(RecordLoanRepayment::class)->execute($loan,['idempotency_key'=>'repay-002','channel'=>'cash','amount_minor'=>20000]);app(ReverseLoanRepayment::class)->execute($repayment,'Cash entry error');$this->assertSame(117000,$loan->refresh()->outstanding_minor);$this->assertSame(0,$loan->installments()->first()->amount_paid_minor);}}
